"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[9355],{7464:(e,t,n)=>{n.d(t,{A:()=>a});const a=n.p+"assets/images/bcn-collage-e089cb7a16f97b5282c6f179b87d5a14.jpg"},19404:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>h,contentTitle:()=>i,default:()=>c,frontMatter:()=>r,metadata:()=>a,toc:()=>l});var a=n(27728),s=n(74848),o=n(28453);const r={title:"Sage Workshop at DISCOVER-US",authors:"pbeckman",tags:["Workshop"]},i=void 0,h={authorsImageUrls:[void 0]},l=[{value:"The Workshop at a Glance",id:"the-workshop-at-a-glance",level:3},{value:"Format and Flow",id:"format-and-flow",level:3},{value:"Session Highlights",id:"session-highlights",level:3},{value:"Cross-Cutting Scientific Questions and Novel Insights",id:"cross-cutting-scientific-questions-and-novel-insights",level:3},{value:"Follow-Ups and Next Steps",id:"follow-ups-and-next-steps",level:3}];function d(e){const t={a:"a",em:"em",h3:"h3",img:"img",p:"p",strong:"strong",...(0,o.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.p,{children:(0,s.jsx)(t.img,{alt:"DISCOVER-US workshop photo collage",src:n(7464).A+"",width:"1714",height:"360"})}),"\n",(0,s.jsx)(t.h3,{id:"the-workshop-at-a-glance",children:"The Workshop at a Glance"}),"\n",(0,s.jsxs)(t.p,{children:["From May 4 to May 6, 2026, roughly forty researchers from across the United States and Europe gathered in Barcelona for an intentionally small, conversation-driven workshop on ",(0,s.jsx)(t.em,{children:"AI and Edge Computing for Scientific Research"}),". The meeting was hosted at ",(0,s.jsx)(t.a,{href:"https://www.upc.edu/en",children:"Universitat Polit\xe8cnica de Catalunya (UPC)"}),", directly next to the ",(0,s.jsx)(t.a,{href:"https://www.bsc.es/",children:"Barcelona Supercomputing Center (BSC)"}),", and was supported by ",(0,s.jsx)(t.a,{href:"https://www.discover-us.eu/",children:"DISCOVER-US"}),", the EU project building transatlantic research collaboration in advanced computing. The workshop was organized by Pete Beckman (",(0,s.jsx)(t.a,{href:"https://www.northwestern.edu/",children:"Northwestern University"}),"), Nicola Ferrier (",(0,s.jsx)(t.a,{href:"https://www.anl.gov/",children:"Argonne National Laboratory"})," / ",(0,s.jsx)(t.a,{href:"https://www.northwestern.edu/",children:"Northwestern"}),"), and Rosa M. Badia (",(0,s.jsx)(t.a,{href:"https://www.bsc.es/",children:"BSC"}),"), with a welcome led by Koen De Bosschere (",(0,s.jsx)(t.a,{href:"https://www.ugent.be/en",children:"Ghent University"}),") on behalf of DISCOVER-US."]}),"\n",(0,s.jsxs)(t.p,{children:["The participant list was deliberately broad. Ecologists and biodiversity researchers from LTER Spain, ",(0,s.jsx)(t.a,{href:"https://www.donanareservas.com/en/",children:"Do\xf1ana National Park"}),", the ",(0,s.jsx)(t.a,{href:"https://www.darwinfoundation.org/en/",children:"Charles Darwin Foundation"}),", ",(0,s.jsx)(t.a,{href:"https://www.neonscience.org/",children:"NEON"}),", UC Davis, Maine, Idaho, Wisconsin, and Iowa State sat alongside computer scientists and AI/orchestration specialists from BSC, Argonne National Laboratory, Northwestern, Ohio State's Imageomics Institute, UPV, INRIA, CEA, CSIC, and Utah; hazards researchers from BSC and GEO3BCN; and deployment leaders from NEON, ",(0,s.jsx)(t.a,{href:"https://ameriflux.lbl.gov/",children:"AmeriFlux"}),", the ",(0,s.jsx)(t.a,{href:"https://cassn.org/",children:"California Bio Sentinel network"}),", and the ",(0,s.jsx)(t.a,{href:"https://sagecontinuum.org/about",children:"Sage Grande Testbed"}),". The roughly even US/EU balance was intentional."]}),"\n",(0,s.jsx)(t.h3,{id:"format-and-flow",children:"Format and Flow"}),"\n",(0,s.jsxs)(t.p,{children:["The three-day program followed a deliberate rhythm: short framing talks to set the intellectual stage, lightning talks from domain experts, and then structured breakout discussions where small groups wrestled with a small number of carefully worded questions. Monday afternoon opened with the DISCOVER-US welcome and a talk providing an overview of the Sage Grande Testbed for AI, followed by the first thematic session. Tuesday packed in three full sessions and a long final discussion block; Wednesday closed the workshop with follow-up discussion, collaboration scoping, and final remarks. A visit to the ",(0,s.jsx)(t.a,{href:"https://www.bsc.es/marenostrum",children:"MareNostrum supercomputer"})," at BSC and a workshop dinner at Restaurant Santa Clara added time for the more informal conversations that often produce the most durable collaborations."]}),"\n",(0,s.jsx)(t.h3,{id:"session-highlights",children:"Session Highlights"}),"\n",(0,s.jsx)(t.p,{children:"The four thematic sessions worked through the problem space from complementary angles."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Session 1 (Ecology and Biodiversity)"})," was framed by Anne Fouilloux (LifeWatch) and Christine Kreuder Johnson (UC Davis), with lightning talks from Joana Colomer (LTER Spain / Minuartia), Nicolas Moity (Charles Darwin Foundation, Gal\xe1pagos), Sydne Record (University of Maine), and Rachel Poretsky (UIC)."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Session 2 (Computer Science \u2014 AI and Orchestration)"})," was framed by Nicola Ferrier on AI and Francesc Lordan (BSC) on distributed computing, with lightning talks from Delia Velasco (CSIC), Elizabeth Tranel (Iowa State), Matthew Thompson (Ohio State), and Germ\xe1n Molt\xf3 (UPV)."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Session 3 (Hazards \u2014 Wildfire and Earthquake)"})," was framed by Josep de la Puente (BSC), with lightning talks from Daniel Balouek (INRIA) and Leonardo Mingari (GEO3BCN)."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Session 4 (Deployments and Networks)"})," was framed by Chris Florian (NEON), with lightning talks from Sebastien Biraud (LBNL) and Gary Bucciarelli (UC Davis). The Wednesday wrap-up added perspectives from Manish Parashar (Utah) on the National Discovery Cloud, Julia McKenna (Northwestern) on the STRONG Manoomin collective, Kyle Kovach (Wisconsin) on hyperspectral sensing, from Josep de la Puente (BSC) on Distributed acoustic sensing, Delia Velasco on the Do\xf1ana Park infrastructure, and others."]}),"\n",(0,s.jsx)(t.h3,{id:"cross-cutting-scientific-questions-and-novel-insights",children:"Cross-Cutting Scientific Questions and Novel Insights"}),"\n",(0,s.jsxs)(t.p,{children:["What made the workshop productive was the way these very different communities converged on the same handful of questions. Across every breakout, participants returned to what makes a scientific question ",(0,s.jsx)(t.em,{children:"transformative"})," and only addressable through AI at the edge: real-time, continuous, multimodal observation; the ability to trigger sampling on events rather than schedules; the move from correlational to causal inference; and the capacity to act, not merely record. Ecologists framed this as detecting short disturbances, species interactions, or shifting baselines that simply do not survive batch upload; computer scientists framed it as autonomous discovery, in-the-wild fine-tuning, and adaptive sampling."]}),"\n",(0,s.jsxs)(t.p,{children:["The vision of an ",(0,s.jsx)(t.em,{children:"agentic edge"})," drew the most energy \u2014 and the most caution. Participants imagined fleets of edge agents that orchestrate sensing, negotiate interpretations with HPC simulations, and collaborate as peers through publish/subscribe and event-driven architectures, with federated model updates aggregating local knowledge into shared understanding without moving raw data. Equally, they catalogued the hard problems: trust, verifiability, uncertainty quantification, safety certification, prompt injection, credential delegation, and the self-reinforcing biases that emerge when agents learn from each other. A recurring move was the shift from ",(0,s.jsx)(t.em,{children:"standardization"})," to ",(0,s.jsx)(t.em,{children:"interoperability"}),' \u2014 accepting that networks will not converge on a single schema, and that the more tractable goal is for agents to translate between FAIR-aligned metadata, ontologies, and APIs. Several groups argued for "thin edge, smart cloud" architectures that do the minimum necessary in the field and push the rest upward.']}),"\n",(0,s.jsxs)(t.p,{children:["A few phrases captured the room. ",(0,s.jsx)(t.em,{children:'"Bringing the office to the sensor"'})," reframed what agentic field campaigns might feel like for working scientists. The provocation that orchestration may need its own ",(0,s.jsx)(t.em,{children:'"vibe coding"'})," revolution surfaced both enthusiasm and serious questions about who reviews AI-generated workflows."]}),"\n",(0,s.jsx)(t.h3,{id:"follow-ups-and-next-steps",children:"Follow-Ups and Next Steps"}),"\n",(0,s.jsxs)(t.p,{children:["The Wednesday collaboration session produced a concrete set of threads to pursue. Manish Parashar, Josep de la Puente, and Domenico Giardini agreed to scope a partnership around the Bedretto Lab data stream. Joana Colomer, Llu\xeds Brotons, and Gene Kelly opened a conversation on connecting US LTER with ILTER and bringing Sage to LTER and Do\xf1ana sites. The group identified the ",(0,s.jsx)(t.a,{href:"https://cassn.org/",children:"Bio Sentinel network"})," as a strong candidate for a first transatlantic deployment, with the next step being to identify a European partner; there was particular interest in bats as a use case. Other threads included an ESIIL hackathon, a possible HiPEAC workshop, and an emerging recognition that nature-risk finance is creating real demand for pre-competitive biodiversity data infrastructure."]}),"\n",(0,s.jsxs)(t.p,{children:["On funding, the group mapped several pathways worth exploring in parallel: an NSF EAGER, NGI Transoceanic open calls, an EU COST Action, and SBIR-style industry partnerships. The shared sentiment was captured in one of the workshop's better lines: ",(0,s.jsx)(t.em,{children:"be reckless with interdisciplinary boundaries"}),". The workshop closed with broad agreement that this group \u2014 and this conversation \u2014 should continue."]})]})}function c(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},27728:e=>{e.exports=JSON.parse('{"permalink":"/news/2026/05/06/sage-workshop-at-discover-us","editUrl":"https://github.com/waggle-sensor/sage-website/edit/main/news/2026-05-06-sage-workshop-at-discover-us.md","source":"@site/news/2026-05-06-sage-workshop-at-discover-us.md","title":"Sage Workshop at DISCOVER-US","description":"DISCOVER-US workshop photo collage","date":"2026-05-06T00:00:00.000Z","tags":[{"inline":true,"label":"Workshop","permalink":"/news/tags/workshop"}],"readingTime":5.2,"hasTruncateMarker":true,"authors":[{"name":"Pete Beckman","title":"Director","imageURL":"https://www.hipeac.net/images/25/22745/square-1759396184.jpg","key":"pbeckman","page":null}],"frontMatter":{"title":"Sage Workshop at DISCOVER-US","authors":"pbeckman","tags":["Workshop"]},"unlisted":false,"nextItem":{"title":"Thor-blade Node Deployments at CPER and GLEES","permalink":"/news/2026/04/06/sage-thor-blade-deployments-at-cper-and-glees"}}')},28453:(e,t,n)=>{n.d(t,{R:()=>r,x:()=>i});var a=n(96540);const s={},o=a.createContext(s);function r(e){const t=a.useContext(o);return a.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function i(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),a.createElement(o.Provider,{value:t},e.children)}}}]);